struct Syntax_Node {
  Node_Kind       kind;
  Source_Location location;
  Type_Info      *type;
  Symbol         *symbol;
  struct Interp_List *interps;
  bool            folded_valid;
  double          folded_value;

  union {

    struct {
      int64_t      value;
      Big_Integer *big_value;
    } integer_lit;

    struct {
      double    value;
      Big_Real *big_value;
      Rational *rational_value;
    } real_lit;

    struct {
      String_Slice text;
      bool         is_parenthesized;
    } string_val;

    struct {
      Syntax_Node *prefix;
      String_Slice selector;
      int32_t component_index;
    } selected;

    struct {
      Syntax_Node   *prefix;
      String_Slice   name;
      Attribute_Kind kind;
      Node_List      arguments;
    } attribute;

    struct {
      Syntax_Node *subtype_mark;
      Syntax_Node *expression;
    } qualified;

    struct {
      Token_Kind   op;
      Syntax_Node *left;
      Syntax_Node *right;
    } binary;

    struct {
      Token_Kind   op;
      Syntax_Node *operand;
    } unary;

    struct {
      Node_List items;
      bool      is_named;
      bool      is_parenthesized;
    } aggregate;

    struct {
      Syntax_Node *subtype_mark;
      Syntax_Node *expression;
      Type_Info   *target_access_type;
    } allocator;

    struct {
      Syntax_Node          *prefix;
      Node_List             arguments;
      Apply_Resolution_Kind resolution;
    } apply;

    struct {
      Syntax_Node *low;
      Syntax_Node *high;
      Syntax_Node *subtype_mark;
    } range;

    struct {
      Node_List    choices;
      Syntax_Node *expression;
    } association;

    struct {
      Syntax_Node *subtype_mark;
      Syntax_Node *constraint;
      bool         is_box;
    } subtype_ind;

    struct {
      Node_List ranges;
    } index_constraint;

    struct {
      Syntax_Node *range;
    } range_constraint;

    struct {
      Node_List associations;
    } discriminant_constraint;

    struct {
      Syntax_Node *digits_expr;
      Syntax_Node *range;
    } digits_constraint;

    struct {
      Syntax_Node *delta_expr;
      Syntax_Node *range;
    } delta_constraint;

    struct {
      Node_List    indices;
      Syntax_Node *component_type;
      bool         is_constrained;
    } array_type;

    struct {
      Node_List    discriminants;
      Node_List    components;
      Syntax_Node *variant_part;
      bool         is_null;
    } record_type;

    struct {
      Syntax_Node *designated;
      bool         is_constant;
    } access_type;

    struct {
      Syntax_Node *parent_type;
      Syntax_Node *constraint;
    } derived_type;

    struct {
      Node_List literals;
    } enum_type;

    struct {
      Syntax_Node *range;
      uint128_t    modulus;
      bool         is_modular;
    } integer_type;

    struct {
      Syntax_Node *precision;
      Syntax_Node *range;
      Syntax_Node *delta;
    } real_type;

    struct {
      Node_List    names;
      Syntax_Node *component_type;
      Syntax_Node *init;
    } component;

    struct {
      String_Slice discriminant;
      Node_List    variants;
    } variant_part;

    struct {
      Node_List    choices;
      Node_List    components;
      Syntax_Node *variant_part;
    } variant;

    struct {
      Node_List    names;
      Syntax_Node *disc_type;
      Syntax_Node *default_expr;
    } discriminant;

    struct {
      Syntax_Node *target;
      Syntax_Node *value;
    } assignment;

    struct {
      Syntax_Node *expression;
    } return_stmt;

    struct {
      Syntax_Node *condition;
      Node_List    then_stmts;
      Node_List    elsif_parts;
      Node_List    else_stmts;
    } if_stmt;

    struct {
      Syntax_Node *expression;
      Node_List    alternatives;
    } case_stmt;

    struct {
      String_Slice  label;
      Symbol       *label_symbol;
      Syntax_Node  *iteration_scheme;
      Node_List     statements;
      bool          is_reverse;
    } loop_stmt;

    struct {
      String_Slice label;
      Symbol      *label_symbol;
      Node_List    declarations;
      Node_List    statements;
      Node_List    handlers;
      bool         is_task_master;
      uint32_t     master_scope_id;
    } block_stmt;

    struct {
      String_Slice  loop_name;
      Syntax_Node  *condition;
      Symbol       *target;
    } exit_stmt;

    struct {
      String_Slice name;
      Symbol      *target;
    } goto_stmt;

    struct {
      String_Slice  name;
      Syntax_Node  *statement;
      Symbol       *symbol;
    } label_node;

    struct {
      Syntax_Node *exception_name;
    } raise_stmt;

    struct {
      String_Slice  entry_name;
      Syntax_Node  *index;
      Node_List     parameters;
      Node_List     statements;
      uint32_t      body_count;
      Symbol       *entry_sym;
      Syntax_Node  *guard;
      uint32_t codegen_index_slot;
    } accept_stmt;

    struct {
      Node_List    alternatives;
      Syntax_Node *else_part;
    } select_stmt;

    struct {
      Syntax_Node *expression;
      Syntax_Node *guard;
    } delay_stmt;

    struct {
      Syntax_Node *guard;
    } null_stmt;

    struct {
      Node_List task_names;
    } abort_stmt;

    struct {
      Node_List    names;
      Syntax_Node *object_type;
      Syntax_Node *init;
      bool         is_constant;
      bool         is_aliased;
      bool         is_rename;
    } object_decl;

    struct {
      String_Slice  name;
      Node_List     discriminants;
      Syntax_Node  *definition;
      bool          is_limited;
      bool          is_private;
    } type_decl;

    struct {
      Node_List    names;
      Syntax_Node *renamed;
    } exception_decl;

    struct {
      String_Slice  name;
      Node_List     parameters;
      Syntax_Node  *return_type;
      Syntax_Node  *renamed;
    } subprogram_spec;

    struct {
      Syntax_Node *specification;
      Node_List    declarations;
      Node_List    statements;
      Node_List    handlers;
      bool         is_separate;
      bool         code_generated;
      bool         is_task_master;
      uint32_t     master_scope_id;
    } subprogram_body;

    struct {
      String_Slice name;
      Node_List    visible_decls;
      Node_List    private_decls;

      uint32_t     pending_activation_first;
      uint32_t     pending_activation_count;
    } package_spec;

    struct {
      String_Slice name;
      Node_List    declarations;
      Node_List    statements;
      Node_List    handlers;
      bool         is_separate;
      bool         elab_generated;
      Scope       *enclosing_body_scope;
    } package_body;

    struct {
      String_Slice  new_name;
      Syntax_Node  *old_name;
    } package_renaming;

    struct {
      String_Slice name;
      Node_List    entries;
      bool         is_type;
    } task_spec;

    struct {
      String_Slice name;
      Node_List    declarations;
      Node_List    statements;
      Node_List    handlers;
      bool         is_separate;
      bool         is_task_master;
      uint32_t     master_scope_id;
    } task_body;

    struct {
      String_Slice name;
      Node_List    parameters;
      Node_List    index_constraints;
    } entry_decl;

    struct {
      Node_List    names;
      Syntax_Node *param_type;
      Syntax_Node *default_expr;
      Parameter_Mode_Kind mode;
    } param_spec;

    struct {
      Node_List    formals;
      Syntax_Node *unit;
    } generic_decl;

    struct {
      Syntax_Node *generic_name;
      Node_List    actuals;
      String_Slice instance_name;
      Token_Kind   unit_kind;
    } generic_inst;

    struct {
      String_Slice     name;
      Generic_Def_Kind def_kind;
      Syntax_Node     *def_detail;
      Node_List        discriminants;
    } generic_type_param;

    struct {
      Node_List        names;
      Syntax_Node     *object_type;
      Syntax_Node     *default_expr;
      Parameter_Mode_Kind mode;
    } generic_object_param;

    struct {
      String_Slice  name;
      Node_List     parameters;
      Syntax_Node  *return_type;
      Syntax_Node  *default_name;
      bool          is_function;
      bool          default_box;
    } generic_subprog_param;

    struct {
      Node_List names;
    } use_clause;

    struct {
      String_Slice name;
      Node_List    arguments;
    } pragma_node;

    struct {
      Node_List exceptions;
      Node_List statements;
    } handler;

    struct {
      Syntax_Node   *entity_name;
      String_Slice   attribute;
      Attribute_Kind attribute_kind;
      Syntax_Node   *expression;
      Node_List    component_clauses;
      bool         is_record_rep;
      bool         is_enum_rep;
      bool         is_address_clause;
    } rep_clause;

    struct {
      Node_List with_clauses;
      Node_List use_clauses;
      Node_List pragmas;
    } context;

    struct {
      Syntax_Node *context;
      Syntax_Node *unit;
      Syntax_Node *separate_parent;
      bool grafted_into_generic;
      bool context_inherited;
    } compilation_unit;
  };
};

