  Emit ("@__exc.program_error    = linkonce_odr constant [14 x i8] c\"PROGRAM_ERROR\\00\"\n");
  Emit ("@__exc.storage_error    = linkonce_odr constant [14 x i8] c\"STORAGE_ERROR\\00\"\n");
