  Emit ("@__heap_used = linkonce_odr global i64 0\n");
  Emit ("define linkonce_odr ptr @__ada_allocate(i64 %%size) {\n");
  Emit ("entry:\n");
  Emit ("  %%used = load i64, ptr @__heap_used\n");
  Emit ("  %%new = add i64 %%used, %%size\n");
  Emit ("  %%over = icmp sgt i64 %%new, 268435456  ; 256 MiB budget\n");
  Emit ("  br i1 %%over, label %%raise, label %%try\n");
  Emit ("try:\n");
  Emit ("  %%p = call ptr @malloc (i64 %%size)\n");
  Emit ("  %%isnull = icmp eq ptr %%p, null\n");
  Emit ("  br i1 %%isnull, label %%raise, label %%ok\n");
  Emit ("ok:\n");
  Emit ("  store i64 %%new, ptr @__heap_used\n");
  Emit ("  ret ptr %%p\n");
  Emit ("raise:\n");
  Emit ("  %%e = ptrtoint ptr @__exc.storage_error to " PTR_INT_TYPE "\n");
  Emit ("  call void @__ada_raise(i64 %%e)\n");
  Emit ("  unreachable\n");
  Emit ("}\n\n");

  Emit ("@__stk_anchor = linkonce_odr thread_local global i64 0\n");
  Emit ("@__stk_limit  = linkonce_odr global i64 0\n");
  Emit ("define linkonce_odr void @__ada_stack_check(i64 %%size) {\n");
  Emit ("entry:\n");
  Emit ("  %%here_p = alloca i8\n");
  Emit ("  %%here = ptrtoint ptr %%here_p to i64\n");
  Emit ("  %%a0 = load i64, ptr @__stk_anchor\n");
  Emit ("  %%fresh = icmp eq i64 %%a0, 0\n");
